          entries={terminalEntries}
          conversations={filteredConversations}
          onClear={() => persistTerminal([])}
          onClearConversation={clearTerminalForConversation}
          onRunsChanged={() => {
            void handleRefresh();
          }}
          onNavigate={navigate}

